import React from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { DashboardIcon, ClassifierIcon, ChatIcon, AboutIcon } from './Icons';

const navItems = [
  { label: 'Dashboard', path: '/dashboard', icon: DashboardIcon },
  { label: 'Classifier', path: '/classifier', icon: ClassifierIcon },
  { label: 'Chat', path: '/chat', icon: ChatIcon },
  { label: 'About', path: '/about', icon: AboutIcon },
];

export default function Sidebar({ open, onClose, session, onLogout, predictionHistory, chatHistory, restorePrediction, restoreChat, collapsed, onToggleCollapse, theme }) {
  const navigate = useNavigate();

  const handlePredictionClick = (item) => {
    restorePrediction(item);
    navigate('/classifier');
    onClose();
  };

  const handleChatClick = (item) => {
    restoreChat(item);
    navigate('/chat');
    onClose();
  };

  return (
    <aside className={`fixed top-0 left-0 z-20 min-h-screen transition-all duration-200 ease-in-out ${
      collapsed ? 'w-16' : 'w-72'
    } ${open ? 'translate-x-0' : '-translate-x-full'} md:translate-x-0 ${
      theme === 'dark' ? 'bg-gray-800 border-gray-700' : 'bg-white border-gray-200'
    } border-r shadow-lg`}>
      <div className="flex flex-col h-full p-6">
        <div className="flex items-center gap-4 mb-10">
          <div className={`w-11 h-11 rounded-xl flex items-center justify-center font-bold transition-colors ${
            theme === 'dark' ? 'bg-purple-600 text-white' : 'bg-purple-100 text-purple-600'
          }`}>
            B
          </div>
          {!collapsed && (
            <div>
              <h1 className="text-lg font-semibold leading-tight">Bovine Classifier</h1>
              <p className={`text-sm ${theme === 'dark' ? 'text-gray-400' : 'text-gray-600'}`}>
                Breed intelligence dashboard
              </p>
            </div>
          )}
        </div>

        <nav className="space-y-2 mb-10">
          {navItems.map((item) => {
            const Icon = item.icon;
            return (
              <NavLink
                key={item.path}
                to={item.path}
                className={({ isActive }) => `flex items-center gap-2 px-3 py-2 rounded-xl text-sm font-medium transition-all duration-200 ${
                  isActive
                    ? theme === 'dark'
                      ? 'bg-purple-600 text-white'
                      : 'bg-purple-100 text-purple-900'
                    : theme === 'dark'
                      ? 'text-gray-300 hover:bg-gray-700 hover:text-white'
                      : 'text-gray-600 hover:bg-gray-100 hover:text-gray-900'
                } ${collapsed ? 'justify-center px-2' : ''}`}
                onClick={onClose}
                title={collapsed ? item.label : undefined}
              >
                <Icon className={`w-4 h-4 flex-shrink-0 ${collapsed ? 'w-4 h-4' : ''}`} />
                {!collapsed && <span>{item.label}</span>}
              </NavLink>
            );
          })}
        </nav>

        {!collapsed && (
          <div className="flex-1">
            <div className={`text-xs font-semibold uppercase tracking-wider mb-4 ${
              theme === 'dark' ? 'text-gray-400' : 'text-gray-500'
            }`}>
              History
            </div>

            <div className="space-y-3 mb-6">
              <div className="text-sm font-semibold text-gray-900 dark:text-white">
                Predictions
              </div>
              {predictionHistory.length ? (
                predictionHistory.slice(0, 4).map((item) => (
                  <button
                    type="button"
                    key={item.id}
                    className={`w-full p-3 rounded-xl text-left transition-all duration-200 ${
                      theme === 'dark'
                        ? 'bg-gray-700 hover:bg-gray-600 text-gray-200 border border-gray-600'
                        : 'bg-gray-50 hover:bg-gray-100 text-gray-700 border border-gray-200'
                    }`}
                    onClick={() => handlePredictionClick(item)}
                  >
                    <div className="text-sm font-medium">{item.breedName}</div>
                    <div className={`text-xs ${theme === 'dark' ? 'text-gray-400' : 'text-gray-500'}`}>
                      {new Date(item.createdAt).toLocaleDateString()}
                    </div>
                  </button>
                ))
              ) : (
                <div className={`text-sm ${theme === 'dark' ? 'text-gray-400' : 'text-gray-500'}`}>
                  No saved predictions yet
                </div>
              )}
            </div>

            <div className="space-y-3">
              <div className="text-sm font-semibold text-gray-900 dark:text-white">
                Chat sessions
              </div>
              {chatHistory.length ? (
                chatHistory.slice(0, 4).map((item) => (
                  <button
                    type="button"
                    key={item.id}
                    className={`w-full p-3 rounded-xl text-left transition-all duration-200 ${
                      theme === 'dark'
                        ? 'bg-gray-700 hover:bg-gray-600 text-gray-200 border border-gray-600'
                        : 'bg-gray-50 hover:bg-gray-100 text-gray-700 border border-gray-200'
                    }`}
                    onClick={() => handleChatClick(item)}
                  >
                    <div className="text-sm font-medium">{item.title}</div>
                    <div className={`text-xs ${theme === 'dark' ? 'text-gray-400' : 'text-gray-500'}`}>
                      {new Date(item.createdAt).toLocaleDateString()}
                    </div>
                  </button>
                ))
              ) : (
                <div className={`text-sm ${theme === 'dark' ? 'text-gray-400' : 'text-gray-500'}`}>
                  No chats yet
                </div>
              )}
            </div>
          </div>
        )}

        <div className={`flex items-center gap-3 p-4 border-t ${
          theme === 'dark' ? 'border-gray-700 bg-gray-800' : 'border-gray-200 bg-gray-50'
        }`}>
          <div className={`w-10 h-10 rounded-full flex items-center justify-center text-sm font-semibold ${
            theme === 'dark' ? 'bg-purple-600 text-white' : 'bg-purple-100 text-purple-900'
          }`}>
            {session?.username?.charAt(0).toUpperCase()}
          </div>
          {!collapsed && (
            <div className="flex-1 min-w-0">
              <div className={`text-sm font-medium truncate ${
                theme === 'dark' ? 'text-white' : 'text-gray-900'
              }`}>
                {session?.username}
              </div>
              <div className={`text-xs truncate ${
                theme === 'dark' ? 'text-gray-400' : 'text-gray-500'
              }`}>
                {session?.email}
              </div>
            </div>
          )}
          <button
            type="button"
            className={`p-2 rounded-lg transition-all duration-200 ${
              theme === 'dark'
                ? 'text-gray-400 hover:text-white hover:bg-gray-700'
                : 'text-gray-500 hover:text-gray-700 hover:bg-gray-100'
            }`}
            onClick={onLogout}
            title="Logout"
          >
            {!collapsed ? (
              <span className="text-sm font-medium">Logout</span>
            ) : (
              <span className="text-lg">×</span>
            )}
          </button>
        </div>
        <button
          type="button"
          className={`absolute top-4 -right-4 w-8 h-8 rounded-full shadow-lg transition-all duration-200 ${
            theme === 'dark'
              ? 'bg-gray-800 border border-gray-700 text-gray-300 hover:bg-gray-700'
              : 'bg-white border border-gray-200 text-gray-600 hover:bg-gray-50'
          }`}
          onClick={onToggleCollapse}
        >
          {collapsed ? '→' : '←'}
        </button>
      </div>
      <motion.button
        className="fixed inset-0 bg-black bg-opacity-50 md:hidden"
        initial={{ opacity: 0 }}
        animate={{ opacity: open ? 1 : 0 }}
        exit={{ opacity: 0 }}
        onClick={onClose}
      />
    </aside>
  );
}
